#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <fcntl.h>
#include <string.h>

int main() {
 const char *fifo_path = "/tmp/myfifo";
 int fd;
 char message[] = "Hello from writer!\n";

 // Open FIFO for writing (blocks until reader opens)
 fd = open(fifo_path, O_WRONLY);
 if (fd == -1) {
 perror("open failed");
 return 1;
 }

 // Write to FIFO
 write(fd, message, strlen(message));
 printf("Message written to FIFO\n");

 close(fd);
 return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <fcntl.h>

int main() {
 const char *fifo_path = "/tmp/myfifo";
 int fd;
 char buffer[1024];
 ssize_t bytes_read;

 // Open FIFO for reading (blocks until writer opens)
 fd = open(fifo_path, O_RDONLY);
 if (fd == -1) {
 perror("open failed");
 return 1;
 }

 // Read from FIFO
 bytes_read = read(fd, buffer, sizeof(buffer) - 1);
 if (bytes_read > 0) {
 buffer[bytes_read] = '\0';
 printf("Received: %s", buffer);
 }

 close(fd);
 return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <fcntl.h>
#include <errno.h>

int main() {
 const char *fifo_path = "/tmp/myfifo";
 int fd;
 char buffer[1024];

 // Open FIFO non-blocking for reading
 fd = open(fifo_path, O_RDONLY | O_NONBLOCK);
 if (fd == -1) {
 perror("open failed");
 return 1;
 }

 // Try to read (won't block)
 ssize_t bytes_read = read(fd, buffer, sizeof(buffer));

 if (bytes_read == -1) {
 if (errno == EAGAIN) {
 printf("No data available (EAGAIN)\n");
 } else {
 perror("read failed");
 }
 } else if (bytes_read == 0) {
 printf("Writer closed FIFO\n");
 } else {
 buffer[bytes_read] = '\0';
 printf("Read: %s\n", buffer);
 }

 close(fd);
 return 0;
}
